# leaf.sh - Beautiful documentation and landing page generator
# Version: 2.2.0
# Generated by hammer.sh

set -euo pipefail

# Colors for output
RED='\\033[0;31m'
GREEN='\\033[0;32m'
YELLOW='\\033[1;33m'
BLUE='\\033[0;34m'
CYAN='\\033[0;36m'
MAGENTA='\\033[0;35m'
NC='\\033[0m' # No Color

# Default configuration
PROJECT_DIR="${1:-.}"
OUTPUT_DIR="${PROJECT_DIR}/docs"
MODE="docs" # docs or landing
LOGO_PATH=""
BASE_PATH="/"
GITHUB_URL="https://github.com/butter-sh"
PRIMARY_COLOR="#86efac"
SECONDARY_COLOR="#4ade80"
PROJECTS_FILE=""

# Dependency check
check_dependencies() {
	local missing_deps=()

	if ! command -v yq &>/dev/null; then
		missing_deps+=("yq")
	fi

	if ! command -v jq &>/dev/null; then
		missing_deps+=("jq")
	fi

	if [ ${#missing_deps[@]} -gt 0 ]; then
		log_error "Missing required dependencies: ${missing_deps[*]}"
		log_info "Install yq: https://github.com/mikefarah/yq#install"
		log_info "Install jq: https://stedolan.github.io/jq/download/"
		return 1
	fi

	return 0
}

# Helper functions
log_info() {
	echo -e "${BLUE}ℹ${NC} $1"
}

log_success() {
	echo -e "${GREEN}✓${NC} $1"
}

log_warn() {
	echo -e "${YELLOW}⚠${NC} $1"
}

log_error() {
	echo -e "${RED}✗${NC} $1"
}

log_debug() {
	if [[ "${DEBUG:-0}" == "1" ]]; then
		echo -e "${MAGENTA}🔍${NC} $1"
	fi
}

