# Parse command line arguments
parse_args() {
	local projects_json=""

	while [[ $# -gt 0 ]]; do
		case $1 in
		-h | --help)
			show_usage
			exit 0
			;;
		--version)
			show_version
			exit 0
			;;
		--debug)
			DEBUG=1
			shift
			;;
		--landing)
			MODE="landing"
			shift
			;;
		--logo)
			LOGO_PATH="$2"
			shift 2
			;;
		--base-path)
			BASE_PATH="$2"
			shift 2
			;;
		--github)
			GITHUB_URL="$2"
			shift 2
			;;
		--projects)
			projects_json="$2"
			shift 2
			;;
		--projects-file)
			PROJECTS_FILE="$2"
			shift 2
			;;
		-o | --output)
			OUTPUT_DIR="$2"
			shift 2
			;;
		-*)
			log_error "Unknown option: $1"
			echo
			show_usage
			exit 1
			;;
		*)
			PROJECT_DIR="$1"
			shift
			;;
		esac
	done

	# Export projects JSON if provided
	if [[ -n "$projects_json" ]]; then
		PROJECTS_JSON="$projects_json"
	fi
}

# Parse YAML using yq
parse_yaml() {
	local file="$1"
	local key="$2"

	if [[ ! -f "$file" ]]; then
		log_debug "YAML file not found: $file"
		echo ""
		return
	fi

	local value=$(yq eval ".${key}" "$file" 2>/dev/null | grep -v '^null$' || echo "")
	log_debug "Parsed ${key} from ${file}: ${value}"
	echo "$value"
}

# Parse and validate JSON using jq
parse_json() {
	local json_input="$1"
	local query="${2:-.}" # Default to identity filter

	log_debug "Parsing JSON with query: $query"

	# Try to parse and validate JSON
	local result
	if result=$(echo "$json_input" | jq -r "$query" 2>/dev/null); then
		log_debug "JSON parsed successfully"
		echo "$result"
		return 0
	else
		log_error "Invalid JSON format"
		return 1
	fi
}

# Validate JSON structure for projects
validate_projects_json() {
	local json="$1"

	log_debug "Validating projects JSON structure"

	# Check if it's an array
	if ! echo "$json" | jq -e 'type == "array"' >/dev/null 2>&1; then
		log_error "Projects JSON must be an array"
		return 1
	fi

	# Check if array is not empty
	local count=$(echo "$json" | jq 'length')
	if [[ "$count" -eq 0 ]]; then
		log_warn "Projects JSON array is empty"
	fi

	log_debug "Found $count project(s) in JSON"

	# Validate each project has required fields
	local i=0
	while [[ $i -lt $count ]]; do
		local project=$(echo "$json" | jq -r ".[$i]")
		local url=$(echo "$project" | jq -r '.url // empty')
		local label=$(echo "$project" | jq -r '.label // empty')

		if [[ -z "$url" || -z "$label" ]]; then
			log_warn "Project at index $i is missing required fields (url, label)"
		else
			log_debug "Project $i: $label -> $url"
		fi

		i=$((i + 1))
	done

	return 0
}

# Read JSON from file
read_json_file() {
	local file="$1"

	if [[ ! -f "$file" ]]; then
		log_error "JSON file not found: $file"
		return 1
	fi

	log_debug "Reading JSON from file: $file"

	local json
	if json=$(jq -c '.' "$file" 2>/dev/null); then
		log_success "JSON file loaded successfully"
		echo "$json"
		return 0
	else
		log_error "Failed to parse JSON file: $file"
		return 1
	fi
}

# Read file content safely
read_file() {
	local file="$1"
	if [[ -f "$file" ]]; then
		cat "$file"
	else
		log_debug "File not found: $file"
		echo ""
	fi
}

# Detect language from file extension
detect_language() {
	local file="$1"
	local ext="${file##*.}"

	case "$ext" in
	sh | bash) echo "bash" ;;
	js) echo "javascript" ;;
	ts) echo "typescript" ;;
	py) echo "python" ;;
	rb) echo "ruby" ;;
	go) echo "go" ;;
	rs) echo "rust" ;;
	java) echo "java" ;;
	c | h) echo "c" ;;
	cpp | cc | cxx | hpp) echo "cpp" ;;
	php) echo "php" ;;
	html | htm) echo "html" ;;
	css) echo "css" ;;
	json) echo "json" ;;
	yaml | yml) echo "yaml" ;;
	xml) echo "xml" ;;
	sql) echo "sql" ;;
	md | markdown) echo "markdown" ;;
	*) echo "plaintext" ;;
	esac
}

# Get icon path
get_icon() {
	# Check if custom logo provided
	if [[ -n "$LOGO_PATH" && -f "$LOGO_PATH" ]]; then
		log_debug "Using custom logo: $LOGO_PATH"
		echo "$LOGO_PATH"
		return
	fi

	local icon_dir="${PROJECT_DIR}/_assets/icon"
	local icon_path=""

	# Search for icon files in priority order
	local icon_files=("icon.svg" "icon-v2.svg" "icon-simple.svg" "icon.png")

	for icon_file in "${icon_files[@]}"; do
		if [[ -f "${icon_dir}/${icon_file}" ]]; then
			icon_path="${icon_dir}/${icon_file}"
			log_debug "Found icon: $icon_path"
			break
		fi
	done

	echo "$icon_path"
}

# Scan source files
scan_source_files() {
	local files=()

	log_debug "Scanning source files in: $PROJECT_DIR"

	while IFS= read -r -d $'\\0' file; do
		local rel_path="${file#${PROJECT_DIR}/}"
		# Skip common directories and minified files
		if [[ "$rel_path" =~ ^(docs|node_modules|\\.git|\\.)|\\.min\\. ]]; then
			continue
		fi
		files+=("$file")
		log_debug "Found source file: $rel_path"
	done < <(find "$PROJECT_DIR" -type f -o -name "*.sh" -o -name "*.bash" -o -name "*.js" -o -name "*.py" -o -name "*.rb" -o -name "*.go" -o -name "*.rs" -print0 2>/dev/null || true)

	printf '%s\
' "${files[@]}"
}

# Scan example files
scan_examples() {
	local examples_dir="${PROJECT_DIR}/examples"
	local examples=()

	if [[ ! -d "$examples_dir" ]]; then
		log_debug "Examples directory not found: $examples_dir"
		return
	fi

	log_debug "Scanning examples in: $examples_dir"

	while IFS= read -r -d $'\\0' file; do
		examples+=("$file")
		log_debug "Found example: ${file#${examples_dir}/}"
	done < <(find "$examples_dir" -type f -print0 2>/dev/null || true)

	printf '%s\
' "${examples[@]}"
}

# Generate documentation page
generate_docs_page() {
	log_info "Generating documentation..."

	local arty_yml="${PROJECT_DIR}/arty.yml"
	local readme_md="${PROJECT_DIR}/README.md"

	# Parse project metadata using yq
	local project_name=$(parse_yaml "$arty_yml" "name")
	local project_version=$(parse_yaml "$arty_yml" "version")
	local project_desc=$(parse_yaml "$arty_yml" "description")
	local project_author=$(parse_yaml "$arty_yml" "author")
	local project_license=$(parse_yaml "$arty_yml" "license")

	# Fallback to directory name if no name in arty.yml
	[[ -z "$project_name" ]] && project_name=$(basename "$PROJECT_DIR")

	log_debug "Project: $project_name v$project_version"
	log_debug "Description: $project_desc"

	# Read README
	local readme_content=$(read_file "$readme_md")
	if [[ -z "$readme_content" ]]; then
		log_warn "README.md not found, using placeholder"
		readme_content="No README.md file found in project."
	fi

	# Get icon
	local icon_path=$(get_icon)
	local icon_svg=""
	if [[ -n "$icon_path" ]]; then
		icon_svg=$(cat "$icon_path")
		log_success "Loaded icon from: ${icon_path#${PROJECT_DIR}/}"
	else
		log_warn "No icon found in _assets/icon/, using default"
	fi

	# Scan files
	local source_files=($(scan_source_files))
	local example_files=($(scan_examples))

	log_info "Found ${#source_files[@]} source files and ${#example_files[@]} examples"

	# Create output directory
	mkdir -p "$OUTPUT_DIR"

	# Generate HTML with all features
	generate_docs_html "$project_name" "$project_version" "$project_desc" "$project_author" "$project_license" "$icon_svg" "$readme_content" "${source_files[@]}" "---" "${example_files[@]}"

	log_success "Documentation generated at: ${OUTPUT_DIR}/index.html"
}

# Generate documentation HTML
