	sed -i "s|%%BASE_PATH%%|${BASE_PATH}|g" "${OUTPUT_DIR}/index.html"
	sed -i "s|%%GITHUB_URL%%|${GITHUB_URL}|g" "${OUTPUT_DIR}/index.html"

	# Handle icon
	if [[ -n "$icon" ]]; then
