# Main function
main() {
	# Check dependencies first
	if ! check_dependencies; then
		exit 1
	fi

	parse_args "$@"

	echo -e "${CYAN}"
	echo "╔═══════════════════════════════════════════╗"
	echo "║                                           ║"
	echo "║      🌿 leaf.sh Generator v2.2 🌿        ║"
	echo "║                                           ║"
	echo "║    Beautiful docs & landing pages        ║"
	echo "║       Powered by yq & jq parsers         ║"
	echo "║                                           ║"
	echo "╚═══════════════════════════════════════════╝"
	echo -e "${NC}"
	echo

	if [[ "$MODE" == "landing" ]]; then
		generate_landing_page
	else
		# Documentation mode
		if [[ ! -d "$PROJECT_DIR" ]]; then
			log_error "Project directory not found: $PROJECT_DIR"
			exit 1
		fi

		log_info "Scanning project: $PROJECT_DIR"
		generate_docs_page
	fi

	echo
	echo -e "${GREEN}═══════════════════════════════════════════${NC}"
	echo -e "${GREEN}Generation complete! 🎉${NC}"
	echo -e "${GREEN}═══════════════════════════════════════════${NC}"
	echo
	echo -e "📂 Output: ${CYAN}${OUTPUT_DIR}/index.html${NC}"
	echo -e "🌐 Open: ${BLUE}file://${OUTPUT_DIR}/index.html${NC}"
	echo
}

# Run main function
main "$@"
